 1	import { type FC, useCallback } from 'react';
 2	
 3	import { BulkSelect, BulkSelectValue } from '@patternfly/react-component-groups';
 4	import { Popover } from '@patternfly/react-core';
 5	import { isEmpty } from '@utils/helpers';
 6	import { useForkliftTranslation } from '@utils/i18n';
 7	
 8	type TableBulkSelectProps = {
 9	  selectedIds: string[];
10	  onSelect: (selectedIds: string[]) => void;
11	  pageDataIds: string[];
12	  dataIds: string[];
13	  canPageSelect?: boolean;
14	};
15	
16	const TOGGLE_CHECKBOX_ID = 'bulk-select-toggle-checkbox';
17	
18	const TableBulkSelect: FC<TableBulkSelectProps> = ({
19	  canPageSelect = true,
20	  dataIds = [],
21	  onSelect,
22	  pageDataIds = [],
23	  selectedIds = [],
24	}) => {
25	  const { t } = useForkliftTranslation();
26	  const pageSelected = pageDataIds.every((item) => selectedIds.includes(item));
27	  const pagePartiallySelected =
28	    pageDataIds.some((item) => selectedIds.includes(item)) && !pageSelected;
29	
30	  const onBulkSelect = useCallback(
31	    (value: BulkSelectValue) => {
32	      switch (value) {
33	        case BulkSelectValue.all:
34	          onSelect(dataIds);
35	          break;
36	        case BulkSelectValue.nonePage:
37	          onSelect(selectedIds.filter((item) => !pageDataIds.includes(item)));
38	          break;
39	        case BulkSelectValue.page:
40	          onSelect(Array.from(new Set([...selectedIds, ...pageDataIds])));
41	          break;
42	        case BulkSelectValue.none:
43	        default:
44	          onSelect([]);
45	      }
46	    },
47	    [selectedIds, pageDataIds, dataIds, onSelect],
48	  );
49	
50	  const bulkSelect = (
51	    <div className="pf-v6-u-text-nowrap">
52	      <BulkSelect
53	        canSelectAll
54	        selectedCount={selectedIds.length}
55	        pageCount={pageDataIds.length}
56	        totalCount={dataIds.length}
57	        onSelect={onBulkSelect}
58	        {...(!isEmpty(pageDataIds) && {
59	          pagePartiallySelected,
60	          pageSelected,
61	        })}
62	        isDataPaginated={canPageSelect}
63	        menuToggleCheckboxProps={{
64	          id: TOGGLE_CHECKBOX_ID,
65	          isDisabled: !canPageSelect,
66	        }}
67	      />
68	    </div>
69	  );
70	
71	  if (canPageSelect) return bulkSelect;
72	
73	  return (
74	    <Popover
75	      triggerAction="hover"
76	      enableFlip
77	      bodyContent={t('Expand folders to show VMs on the current page, then you can select them.')}
78	    >
79	      {bulkSelect}
80	    </Popover>
81	  );
82	};
83	
84	export default TableBulkSelect;

